INSERT INTO "zrl_ai_reports" ("id","round_id","team_id","report_type","content","model","created_at","hash") VALUES(104,4,0,'round',replace('**Analisi tecnica del round e suggerimenti per migliorare la performance del team**\n\n**Classifica attuale**\n\nLa classifica attuale è la seguente:\n\n1. EVO Core HP (42 punti)\n2. Rush Pack eSRT (37 punti)\n3. WattFabrik WattGockel (31 punti)\n4. WATT BoiTTE (21 punti)\n5. Foudre Bourgueil (21 punti)\n6. Ride Club Finland B1 (21 punti)\n7. SISU Racing Drake (17 punti)\n8. TFC Saints (17 punti)\n9. OikR (15 punti)\n10. BIKES FRANCE - Team Frenchy Burritos (12 punti)\n\n**Suggerimenti per migliorare la performance del team**\n\n1. **EVO Core HP**: continuare a giocare con la stessa strategia che ha portato a 42 punti, ma gangliare di più sulle partite decisive.\n2. **Rush Pack eSRT**: prestare attenzione alle partite contro i team più deboli e cercare di vincere con un margine di vantaggio.\n3. **Watt\n\n<!-- AI_METADATA: {"q":80,"c":"0.000242","rid":"d76d5ae5-dabc-4bc4-9af5-e4ad0ad516c0","v":"11.0"} -->','\n',char(10)),'SYSTEM','2026-06-09 19:14:58','0a8965039c1c3ff35d7ee2f621ad595bcd6807f810f2e1ad140b98ff4cbadb5d');
INSERT INTO "zrl_ai_reports" ("id","round_id","team_id","report_type","content","model","created_at","hash") VALUES(106,0,0,'season',replace('**La Stagione di ZRL 2025: Un''Odyssea di Rivalità e Trend**\n\nLa stagione di ZRL 2025 è stata un''epopea di emozioni, di scontri e di trionfi. I team hanno lottato per ogni punto, per ogni vittoria, per ogni posizione nella classifica. Ecco la nostra analisi della stagione, con i suoi protagonisti, i suoi antagonisti e i suoi trend.\n\n**I Primi della Classifica**\n\nIl Team Santysiak Epica FURETTI ha dominato la stagione, con 40 punti in classifica. Hanno vinto 8 gare e hanno avuto una media di 5 punti a gara. Sono stati i favoriti per la vittoria della stagione e non hanno deluso le aspettative.\n\n**La Lotta per la Seconda Posizione**\n\nIl Dirty Sea Donkeys è stato il principale sfidante del Team Santysiak Epica FURETTI. Hanno vinto 7 gare e hanno avuto una media di 4,5 punti a gara. Sono stati i più vicini ai prim\n\n<!-- AI_METADATA: {"q":77,"c":"0.000243","rid":"656dbd27-8f55-4c58-8d04-40da19f17fc4","v":"11.0"} -->','\n',char(10)),'SYSTEM','2026-06-09 19:15:09','b7a1903f7d6c11cd08c1e65b69715daf0dc55c32a5f7051f4386fe3461ea6760');
INSERT INTO "zrl_ai_reports" ("id","round_id","team_id","report_type","content","model","created_at","hash") VALUES(111,4,74016,'race',replace('**INOX FIRE: UN DUETTO VINCENTE E UNA SQUADRA CHE LUCICA**\n\n**RACE 3: UNA GARA DA NON DIMENTICARE**\n\nLa squadra INOX FIRE ha scritto una pagina di storia nella terza gara della stagione, con un duello atletico che ha lasciato tutti a bocca aperta. I nostri cinque corridori, Chris Musgrove, Claudio Varani, Cristian Pelosi, Francesco Ravasi e Giancarlo Rugolo, hanno dimostrato di essere una squadra compatta e determinata, lottando fino all''ultimo metro.\n\n**I PUNTI FAL/FTS: UNA CONFRONTO DA NON DIMENTICARE**\n\nI nostri corridori hanno ottenuto ottimi risultati in termini di punti FAL/FTS. Chris Musgrove si è classificato al primo posto con 47 punti, seguito da Claudio Varani con 25 punti. Cristian Pelosi ha chiuso al terzo posto con 37 punti, mentre Francesco Ravasi e Giancarlo Rugolo hanno ottenuto rispettivamente 22\n\n<!-- AI_METADATA: {"q":80,"c":"0.000057","rid":"f08c42d2-4d51-4a82-b9ac-707a7421923c","v":"11.0"} -->','\n',char(10)),'SYSTEM','2026-06-09 19:27:15','f68f14a05b4fcb13579f3522d663f8f0e7bfc70fb40d70c5c4711033eda630ba');
